const issues = $input.all();
const now = new Date();
const config = $('Fetch Agent Config').item.json?.metadata ?? {};
const staleDays = config.stale_days ?? 3;
const STALE_MS = staleDays * 24 * 60 * 60 * 1000;
const repo = config.repo ?? 'thompsmanlearn/claudis';

let allIssues = [];
for (const item of issues) {
  const data = item.json;
  if (Array.isArray(data)) { allIssues = allIssues.concat(data); }
  else if (data && data.number) { allIssues.push(data); }
}

const openIssues = allIssues.filter(i => !i.pull_request);
const stale = openIssues.filter(issue => (now - new Date(issue.updated_at)) > STALE_MS);
const total_open = openIssues.length;

if (stale.length === 0) {
  return [{ json: { stale_count: 0, total_open, stale_issues: [], repo, stale_days: staleDays,
    message: `✅ GitHub issues (${repo}): ${total_open} open, all active (updated <${staleDays}d).` } }];
}

const formatted = stale.map(issue => ({
  number: issue.number, title: issue.title, url: issue.html_url,
  days_stale: Math.floor((now - new Date(issue.updated_at)) / (24*60*60*1000)),
  labels: (issue.labels || []).map(l => l.name).join(', ')
}));

const lines = [`⚠️ ${stale.length} stale GitHub issue${stale.length > 1 ? 's' : ''} (>${staleDays}d no activity):`, `Repo: ${repo}`];
for (const i of formatted) {
  lines.push(`#${i.number} (${i.days_stale}d) — ${i.title.slice(0,55)}`);
  lines.push(`  ${i.url}`);
}
lines.push(`\nTotal open: ${total_open}`);

return [{ json: { stale_count: stale.length, total_open, stale_issues: formatted, repo, stale_days: staleDays, message: lines.join('\n') } }];
